import * as vscode from "vscode";
import type { SymbolMetrics } from "../core/analyze";
import { sortSymbols, type SortField, symbolsForFile } from "../core/viewModel";
import type { ExtensionState } from "./extensionState";

const SORT_FIELD_LABELS: Record<SortField, string> = { f: "F", fPrime: "F′", g: "G", cc: "CC", crap: "CRAP" };

export type RiskNode =
  | { type: "file"; uri: string; label: string }
  | { type: "symbol"; symbol: SymbolMetrics }
  | { type: "empty"; message: string }
  | { type: "scope"; label: string };

export class RiskTreeProvider implements vscode.TreeDataProvider<RiskNode> {
  private readonly _onDidChange = new vscode.EventEmitter<RiskNode | undefined | null | void>();
  readonly onDidChangeTreeData = this._onDidChange.event;
  private _sortField: SortField = "f";

  constructor(private readonly state: ExtensionState) {}

  setSortField(field: SortField): void {
    this._sortField = field;
    this._onDidChange.fire();
  }

  get sortField(): SortField {
    return this._sortField;
  }

  refresh(): void {
    this._onDidChange.fire();
  }

  getTreeItem(element: RiskNode): vscode.TreeItem {
    if (element.type === "empty") {
      const item = new vscode.TreeItem(element.message, vscode.TreeItemCollapsibleState.None);
      item.iconPath = new vscode.ThemeIcon("info");
      return item;
    }
    if (element.type === "scope") {
      const item = new vscode.TreeItem(element.label, vscode.TreeItemCollapsibleState.None);
      item.iconPath = new vscode.ThemeIcon("root-folder");
      item.contextValue = "ddpScope";
      return item;
    }
    if (element.type === "file") {
      const field = this._sortField;
      const label = SORT_FIELD_LABELS[field];
      const maxVal = Math.max(
        0,
        ...symbolsForFile(element.uri, this.state.lastAnalysis?.symbols ?? []).map((s) => s[field])
      );
      const item = new vscode.TreeItem(element.label, vscode.TreeItemCollapsibleState.Expanded);
      item.description = `max ${label}≈${maxVal.toFixed(0)}`;
      item.iconPath = new vscode.ThemeIcon("file-code");
      item.contextValue = "ddpFile";
      item.command = {
        command: "ddp.riskView.openFile",
        title: "Open file",
        arguments: [vscode.Uri.parse(element.uri)],
      };
      return item;
    }
    const s = element.symbol;
    const item = new vscode.TreeItem(s.name, vscode.TreeItemCollapsibleState.None);
    item.description = `F=${s.f.toFixed(1)}  R=${s.r.toFixed(2)}  CC=${s.cc}  T=${(s.t * 100).toFixed(0)}%`;
    item.tooltip = new vscode.MarkdownString(
      `**${s.name}**\n\nR=${s.r.toFixed(3)}  CRAP=${s.crap.toFixed(2)}  F=${s.f.toFixed(2)}`
    );
    item.command = {
      command: "ddp.revealSymbol",
      title: "Reveal symbol",
      arguments: [s.id],
    };
    return item;
  }

  async getChildren(element?: RiskNode): Promise<RiskNode[]> {
    const analysis = this.state.lastAnalysis;
    if (!analysis?.symbols.length) {
      return element ? [] : [{ type: "empty" as const, message: "Run “DDP: Analyze workspace” (or Refresh)" }];
    }
    if (!element) {
      const rootUri = this.state.lastScope?.rootUri;
      const scopeLabel = rootUri
        ? vscode.Uri.parse(rootUri).fsPath
        : "workspace";
      const scopeNode: RiskNode = { type: "scope", label: scopeLabel };
      const byFile = new Map<string, SymbolMetrics[]>();
      for (const s of analysis.symbols) {
        let list = byFile.get(s.uri);
        if (!list) {
          list = [];
          byFile.set(s.uri, list);
        }
        list.push(s);
      }
      const field = this._sortField;
      const files = [...byFile.entries()].sort((a, b) => {
        const maxA = Math.max(...a[1].map((x) => x[field]));
        const maxB = Math.max(...b[1].map((x) => x[field]));
        return maxB - maxA;
      });
      return [
        scopeNode,
        ...files.map(([uri]) => ({
          type: "file" as const,
          uri,
          label: vscode.Uri.parse(uri).fsPath.split(/[/\\]/).pop() ?? uri,
        })),
      ];
    }
    if (element.type === "file") {
      const list = sortSymbols(symbolsForFile(element.uri, analysis.symbols), this._sortField);
      return list.map((symbol) => ({ type: "symbol" as const, symbol }));
    }
    return [];
  }
}

src/core/analyze.ts.source:
import { crap, failureRiskFromCrap } from "./metrics";
import { computeRanks, type CallEdge, type RankOptions } from "./rank";

/** Input data for a single function/method before metric computation. */
export type SymbolInput = {
  readonly id: string;
  readonly uri: string;
  readonly name: string;
  /** Cyclomatic complexity. */
  readonly cc: number;
  /** Test coverage fraction in [0, 1]. */
  readonly t: number;
};

/** Fully computed metrics for a function/method. */
export type SymbolMetrics = SymbolInput & {
  /** Rank (R) — impact propagation via call graph. */
  readonly r: number;
  /** CRAP score — CC² × (1 − T)³ + CC. */
  readonly crap: number;
  /** Failure risk — F = R × CRAP. */
  readonly f: number;
  /** Churn multiplier (G ≥ 1). 1 until churn is applied. */
  readonly g: number;
  /** Churn-adjusted failure risk — F' = F × G. */
  readonly fPrime: number;
};

/**
 * Compute failure-risk metrics for all symbols.
 *
 * @param edges       Call graph edges (caller → callee).
 * @param symbols     Function/method symbols with CC and coverage.
 * @param rankOptions PageRank convergence parameters.
 * @returns Symbols enriched with rank (R), CRAP, and failure risk (F).
 */
export function computeSymbolMetrics(
  edges: readonly CallEdge[],
  symbols: readonly SymbolInput[],
  rankOptions: Partial<RankOptions> = {}
): SymbolMetrics[] {
  const ranks = computeRanks(edges, rankOptions);
  return symbols.map((symbol) => {
    const rank = ranks.get(symbol.id) ?? 1;
    const crapScore = crap(symbol.cc, symbol.t);
    const failureRisk = failureRiskFromCrap(rank, crapScore);
    return { ...symbol, r: rank, crap: crapScore, f: failureRisk, g: 1, fPrime: failureRisk };
  });
}

