import type { CallEdge } from "../core/rank";
import { edgesFromCallerCallees } from "../core/graphBuilder";

/** Abstraction over VS Code's call hierarchy so orchestration can be tested with fakes. */
export interface CallHierarchyAdapter {
  /** Return all function-level symbols across the workspace as {id, uriStr}. */
  findFunctionSymbols(): Promise<{ id: string; uriStr: string }[]>;
  /** Given a symbol id, return the ids of all callees (outgoing calls). */
  getOutgoingCalleeIds(symbolId: string): Promise<string[]>;
  /** Whether the operation has been cancelled. */
  isCancelled(): boolean;
}

/**
 * Pure orchestration: iterate symbols, collect outgoing edges, build CallEdge[].
 * Self-edges (caller === callee) are filtered. Dedup delegated to edgesFromCallerCallees.
 */
export async function collectCallEdgesViaAdapter(
  adapter: CallHierarchyAdapter
): Promise<CallEdge[]> {
  const symbols = await adapter.findFunctionSymbols();
  const callerCallees: { callerId: string; calleeIds: string[] }[] = [];

  for (const sym of symbols) {
    if (adapter.isCancelled()) {
      break;
    }
    const calleeIds = await adapter.getOutgoingCalleeIds(sym.id);
    const filtered = calleeIds.filter((id) => id !== sym.id);
    if (filtered.length) {
      callerCallees.push({ callerId: sym.id, calleeIds: filtered });
    }
  }

  return edgesFromCallerCallees(callerCallees);
}

src/core/rank.ts.source:
/**
 * Rank (R) propagation: each unit starts at 1; callers add R_caller / outDegree(caller) to each callee.
 * Iterated until convergence (Dependable Dependencies paper, PageRank-like without damping).
 */

export type CallEdge = { readonly caller: string; readonly callee: string };

export type RankOptions = {
  readonly maxIterations: number;
  readonly epsilon: number;
};

/** Build outgoing adjacency: caller -> set of callees (unique). */
export function calleesByCaller(edges: readonly CallEdge[]): Map<string, Set<string>> {
  const map = new Map<string, Set<string>>();
  for (const e of edges) {
    let set = map.get(e.caller);
    if (!set) {
      set = new Set();
      map.set(e.caller, set);
    }
    set.add(e.callee);
  }
  return map;
}

export function allNodeIds(edges: readonly CallEdge[]): Set<string> {
  const ids = new Set<string>();
  for (const e of edges) {
    ids.add(e.caller);
    ids.add(e.callee);
  }
  return ids;
}

/**
 * One synchronous update: R_new(v) = 1 + sum_{u calls v} R_old(u) / outDegree(u).
 * Callers with outDegree 0 contribute nothing (they do not depend on any callee in the graph).
 */
export function rankOneStep(
  nodeIds: ReadonlySet<string>,
  outDegree: ReadonlyMap<string, number>,
  incomingContributions: ReadonlyMap<string, readonly { caller: string }[]>,
  rOld: ReadonlyMap<string, number>
): Map<string, number> {
  const next = new Map<string, number>();
  for (const id of nodeIds) {
    let sum = 0;
    const incoming = incomingContributions.get(id);
    if (incoming) {
      for (const { caller } of incoming) {
        const deg = outDegree.get(caller) ?? 0;
        if (deg > 0) {
          sum += (rOld.get(caller) ?? 1) / deg;
        }
      }
    }
    next.set(id, 1 + sum);
  }
  return next;
}

export function buildIncomingMap(edges: readonly CallEdge[]): Map<string, { caller: string }[]> {
  const callees = calleesByCaller(edges);
  const incoming = new Map<string, { caller: string }[]>();
  for (const [caller, calleesSet] of callees) {
    for (const callee of calleesSet) {
      let list = incoming.get(callee);
      if (!list) {
        list = [];
        incoming.set(callee, list);
      }
      list.push({ caller });
    }
  }
  return incoming;
}

export function outDegreesFromCallees(callees: ReadonlyMap<string, Set<string>>): Map<string, number> {
  const deg = new Map<string, number>();
  for (const [caller, set] of callees) {
    deg.set(caller, set.size);
  }
  return deg;
}

export function hasConverged(
  rOld: ReadonlyMap<string, number>,
  rNew: ReadonlyMap<string, number>,
  epsilon: number
): boolean {
  let maxDelta = 0;
  for (const [id, a] of rOld) {
    const b = rNew.get(id)!;
    maxDelta = Math.max(maxDelta, Math.abs(a - b));
  }
  return maxDelta < epsilon;
}

export function computeRanks(
  edges: readonly CallEdge[],
  { maxIterations = 100, epsilon = 1e-6 }: Partial<RankOptions> = {}
): Map<string, number> {
  const nodeIds = allNodeIds(edges);
  const callees = calleesByCaller(edges);
  const outDeg = outDegreesFromCallees(callees);
  const incoming = buildIncomingMap(edges);

  let r = new Map<string, number>();
  for (const id of nodeIds) {
    r.set(id, 1);
  }

  for (let i = 0; i < maxIterations; i++) {
    const rNext = rankOneStep(nodeIds, outDeg, incoming, r);
    const converged = hasConverged(r, rNext, epsilon);
    r = rNext;
    if (converged) {
      break;
    }
  }
  return r;
}

src/ddp/cc/eslintParse.ts.source:
import { parseComplexityFromMessage } from "./parseComplexity";

type EslintJson = { filePath?: string; messages?: { ruleId?: string; line?: number; message?: string }[] };

export function parseEslintComplexityJson(jsonText: string): Map<number, number> {
  const byLine = new Map<number, number>();
  try {
    const arr = JSON.parse(jsonText) as EslintJson[];
    if (!Array.isArray(arr)) {
      return byLine;
    }
    for (const file of arr) {
      for (const msg of file.messages ?? []) {
        const rid = msg.ruleId ?? "";
        if (
          (rid !== "complexity" && rid !== "@typescript-eslint/complexity") ||
          typeof msg.line !== "number"
        ) {
          continue;
        }
        const n = parseComplexityFromMessage(msg.message ?? "");
        if (n !== undefined) {
          const prev = byLine.get(msg.line) ?? 0;
          byLine.set(msg.line, Math.max(prev, n));
        }
      }
    }
  } catch {
    /* ignore */
  }
  return byLine;
}

export { parseComplexityFromMessage } from "./parseComplexity";

